update hrrmycct set sl_dot = a.sl_dot - b.so_luong
  from hrrmycct a join hrrmdotct b on a.stt_rec = b.stt_rec_yc and a.stt_rec0 = b.stt_rec0yc
  where b.stt_rec = @stt_rec and a.sl_dot > 0

