declare @invoke nvarchar(4000)
select @invoke = ''
&ListDeleted;
&PostDeleted;
select @invoke as invoke






        /* <flatten type="Javascript"> */
var f = this, id = f.get_id(), g = f.getItem('d11')._controlBehavior, v = f._language == 'v';
var l1 = g._getColumnOrder('ma_vtr'), l2 = g._getColumnOrder('ma_bp'), l3 = g._getColumnOrder('so_luong'), error;
var e1 = (v ? 'Thông tin vị trí và bộ phận đã có.' : 'The record consisting of the position and department code already exists.');
var e2 = (v ? 'Trường <span class="Highlight">%s</span> chưa nhập hoặc giá trị nhập không hợp lệ.' : 'Field <span class="Highlight">%s</span> must not be blank or has invalid value.');
var a = query$Select(g, 'count$1,min$so_luong $groupBy ma_bp, ma_vtr');

for (var i = 0; i < a.length; i++) {
  if (a[i][2] > 1) {
    g._errorObject = g._getItem(i + 1, l1);
    f._checked = false;
    error = e1;
    break;
  }
  if (a[i][3] < 0) {
    g._errorObject = g._getItem(i + 1, l3);
    f._checked = false;
    error = e2.replace('%s', g._fields[l3 - 1].HeaderText);
    break;
  }

}
if (!f._checked) {
  $func.hideWait(id);
  $message.show(error, String.format('$find(\'{0}\')._errorObject.focus()', g.get_id()));
  break;
}
/* </flatten> */
